import { createFileRoute, useSearch } from "@tanstack/react-router";
import { useUiPreview } from "../../hooks/use-ui-preview";
import { getColors } from "../../lib/get-colors";
import { Placeholder } from "../../components/placeholder";
import { Examples } from "../../components/ui-preview/examples";
import { Page } from "../../components/ui-preview/page";
import { Section } from "../../components/ui-preview/section";
import { SectionTitle } from "../../components/ui-preview/section-title";
import { StatsAndExamples } from "../../components/ui-preview/stats-and-examples";
import { TokenCol } from "../../components/ui-preview/token-col";
import { TokenColumns } from "../../components/ui-preview/token-columns";
import { ColorTokenGroup } from "../../partials/ui-preview/color-token-group";
import { StatsRow } from "../../partials/ui-preview/stats-row";
import { UiExampleBadges } from "../../partials/ui-preview/ui-example-badges";
import { UiExampleChrome } from "../../partials/ui-preview/ui-example-chrome";
import { UiExampleForm } from "../../partials/ui-preview/ui-example-form";
import { UiExampleText } from "../../partials/ui-preview/ui-example-text";

export const Route = createFileRoute("/preview/ui")({
    component: Component,
});

function Component() {
    const { themeKey } = useSearch({ from: "__root__" });
    const { data, isLoading } = useUiPreview(themeKey);

    if (isLoading || !data) {
        return (
            <Placeholder minHeight={200}>
                <p>Loading…</p>
            </Placeholder>
        );
    }

    const { theme, contrast, paletteColors, darkestPrimary, lightestPrimary, notificationColors } =
        data;

    const colors = getColors(theme);

    return (
        <Page>
            <Section>
                <SectionTitle>
                    {theme.meta.collection.label} :: {theme.meta.name}
                </SectionTitle>

                <TokenColumns>
                    <TokenCol>
                        <ColorTokenGroup
                            label="Primaries — Dark"
                            tokens={[
                                ["d10", colors.primaries.d10],
                                ["d20", colors.primaries.d20],
                                ["d30", colors.primaries.d30],
                                ["d40", colors.primaries.d40],
                            ]}
                        />
                        <ColorTokenGroup
                            label="Primaries — Mid"
                            tokens={[
                                ["m10", colors.primaries.m10],
                                ["m20", colors.primaries.m20],
                                ["m30", colors.primaries.m30],
                                ["m40", colors.primaries.m40],
                            ]}
                        />
                        <ColorTokenGroup
                            label="Primaries — Light"
                            tokens={[
                                ["l10", colors.primaries.l10],
                                ["l20", colors.primaries.l20],
                                ["l30", colors.primaries.l30],
                                ["l40", colors.primaries.l40],
                            ]}
                        />
                    </TokenCol>
                    <TokenCol>
                        <ColorTokenGroup label="Palette" tokens={Object.entries(colors.palette)} />
                        <TokenColumns>
                            <ColorTokenGroup
                                label="UI Backgrounds"
                                tokens={Object.entries(colors.ui.bg).flatMap(([key, val]) =>
                                    typeof val === "string"
                                        ? [[key, val] as [string, string]]
                                        : Object.entries(val).map(([k, v]) =>
                                            [`${key}-${k}`, v as string] as [string, string]
                                        )
                                ) as [string, string][]}
                            />

                            <ColorTokenGroup
                                label="UI Foregrounds"
                                tokens={Object.entries(colors.ui.fg).flatMap(([key, val]) =>
                                    typeof val === "string"
                                        ? [[key, val] as [string, string]]
                                        : Object.entries(val).map(([k, v]) =>
                                            [`${key}-${k}`, v as string] as [string, string]
                                        )
                                ) as [string, string][]}
                                swatchType="foreground"
                            />
                        </TokenColumns>
                    </TokenCol>
                </TokenColumns>
            </Section>

            <StatsAndExamples>
                <StatsRow
                    contrast={contrast}
                    paletteColors={paletteColors}
                    darkestPrimary={darkestPrimary}
                    lightestPrimary={lightestPrimary}
                />

                <Examples>
                    <UiExampleText />
                    <UiExampleChrome />
                    <UiExampleForm />
                    <UiExampleBadges
                        success={notificationColors.success}
                        warning={notificationColors.warning}
                        error={notificationColors.error}
                        info={notificationColors.info}
                    />
                </Examples>
            </StatsAndExamples>
        </Page>
    );
}

import type { ReactNode } from "react";
import styles from "./Page.module.css";

interface Props extends React.HTMLAttributes<HTMLDivElement> {
    children: ReactNode;
}

export function Page({ children, ...rest }: Props) {
    return <div className={styles.page} data-layout="Page" {...rest}>{children}</div>;
}

.page {
    padding: var(--size-5);
    display: flex;
    flex-direction: column;
    gap: var(--size-7);
}

@media (max-width: 768px) {
    .page {
        padding: var(--size-3);
    }
}

import type { ReactNode } from "react";
import styles from "./TokenColumns.module.css";

interface Props {
    children: ReactNode;
}

export function TokenColumns({ children }: Props) {
    return <div className={styles.tokenColumns} data-layout="TokenColumns">{children}</div>;
}

.tokenColumns {
    display: flex;
    gap: var(--size-5);
    align-items: flex-start;
}

import type { ReactNode } from "react";
import styles from "./StatsAndExamples.module.css";

interface Props {
    children: ReactNode;
}

export function StatsAndExamples({ children }: Props) {
    return <div className={styles.statsAndExamples} data-layout="StatsAndExamples">{children}</div>;
}

.statsAndExamples {
    display: flex;
    gap: var(--size-5);
    align-items: flex-start;
}

@media (max-width: 768px) {
    .statsAndExamples {
        flex-direction: column;
    }
}

import type { ReactNode } from "react";
import styles from "./Examples.module.css";

interface Props {
    children: ReactNode;
}

export function Examples({ children }: Props) {
    return <div className={styles.examples} data-layout="Examples">{children}</div>;
}

.examples {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    gap: var(--size-3);
}

import { ColorSwatch } from "../../components/color-swatch";
import { ExampleSection } from "../../components/ui-preview/example-section";
import { SwatchGrid } from "../../components/ui-preview/swatch-grid";

interface Props {
    label: string;
    tokens: [string, string][];
    swatchType?: "background" | "foreground";
}

export function ColorTokenGroup({ label, tokens, swatchType = "background" }: Props) {
    return (
        <ExampleSection label={label} data-partial="ColorTokenGroup">
            <SwatchGrid>
                {tokens.map(([name, color]) => (
                    <ColorSwatch
                        key={name}
                        color={color}
                        label={name}
                        type={swatchType}
                    />
                ))}
            </SwatchGrid>
        </ExampleSection>
    );
}

import { StatCard } from "../../components/stat-card";
import { ContrastDisplay } from "../../components/ui-preview/contrast-display";
import { HueStrip } from "../../components/ui-preview/hue-strip";
import { LightnessBar } from "../../components/ui-preview/lightness-bar";
import { StatsRowLayout } from "../../components/ui-preview/stats-row-layout";

interface ContrastData {
    ratio: number;
    level: "AAA" | "AA" | "fail";
}

interface Props {
    contrast: ContrastData;
    paletteColors: string[];
    darkestPrimary: string;
    lightestPrimary: string;
}

export function StatsRow({
    contrast,
    paletteColors,
    darkestPrimary,
    lightestPrimary,
}: Props) {
    return (
        <StatsRowLayout data-partial="StatsRow">
            <StatCard label="Contrast (fg/bg)">
                <ContrastDisplay ratio={contrast.ratio} grade={contrast.grade} />
            </StatCard>

            <StatCard label="Hue spread">
                <HueStrip colors={paletteColors} />
            </StatCard>

            <StatCard label="Lightness range">
                <LightnessBar from={darkestPrimary} to={lightestPrimary} />
            </StatCard>
        </StatsRowLayout>
    );
}

import { ExampleSection } from "../../components/ui-preview/example-section";
import { StatusItem } from "../../components/ui-preview/status-item";
import { StatusList } from "../../components/ui-preview/status-list";

interface Props {
    success: string;
    warning: string;
    error: string;
    info: string;
}

export function UiExampleBadges({ success, warning, error, info }: Props) {
    const states = [
        { label: "success", color: success, message: "Something happened" },
        { label: "warning", color: warning, message: "Something happened" },
        { label: "error", color: error, message: "Something went wrong" },
        { label: "info", color: info, message: "Something happened" },
    ];

    return (
        <ExampleSection label="Notifications" data-partial="UiExampleBadges">
            <StatusList>
                {states.map(({ label, color, message }) => (
                    <StatusItem key={label} color={color} label={label} message={message} />
                ))}
            </StatusList>
        </ExampleSection>
    );
}

import { ChromeCard } from "../../components/ui-preview/chrome-card";
import { ChromeLayout } from "../../components/ui-preview/chrome-layout";
import { ChromePanel } from "../../components/ui-preview/chrome-panel";
import { ChromeSidebar } from "../../components/ui-preview/chrome-sidebar";
import { ChromeSidebarItem } from "../../components/ui-preview/chrome-sidebar-item";
import { ExampleSection } from "../../components/ui-preview/example-section";

export function UiExampleChrome() {
    return (
        <ExampleSection label="App Chrome" data-partial="UiExampleChrome">
            <ChromeLayout>
                <ChromeSidebar>
                    <ChromeSidebarItem active>Dashboard</ChromeSidebarItem>
                    <ChromeSidebarItem>Settings</ChromeSidebarItem>
                    <ChromeSidebarItem>Profile</ChromeSidebarItem>
                </ChromeSidebar>
                <ChromePanel header="Dashboard">
                    <ChromeCard>Content area</ChromeCard>
                    <ChromeCard>Another panel</ChromeCard>
                </ChromePanel>
            </ChromeLayout>
        </ExampleSection>
    );
}

import { Button } from "../../components/ui-preview/button";
import { ButtonGroup } from "../../components/ui-preview/button-group";
import { ExampleSection } from "../../components/ui-preview/example-section";
import { FormInput } from "../../components/ui-preview/form-input";
import { FormPanel } from "../../components/ui-preview/form-panel";

export function UiExampleForm() {
    return (
        <ExampleSection label="Form Elements" data-partial="UiExampleForm">
            <FormPanel>
                <FormInput placeholder="Input field" readOnly />
                <ButtonGroup>
                    <Button variant="primary" type="button">Primary</Button>
                    <Button variant="secondary" type="button">Secondary</Button>
                    <Button variant="secondary" type="button" disabled>Disabled</Button>
                </ButtonGroup>
            </FormPanel>
        </ExampleSection>
    );
}

import { ExampleSection } from "../../components/ui-preview/example-section";
import { TypographyExample } from "../../components/ui-preview/typography-example";

export function UiExampleText() {
    return (
        <ExampleSection label="Text Content" data-partial="UiExampleText">
            <TypographyExample />
        </ExampleSection>
    );
}

import type { ReactNode } from "react";
import styles from "./Section.module.css";

interface Props {
    children: ReactNode;
}

export function Section({ children }: Props) {
    return <section className={styles.section} data-layout="Section">{children}</section>;
}

import type { ReactNode } from "react";
import styles from "./ExampleSection.module.css";

interface Props extends React.HTMLAttributes<HTMLDivElement> {
    label: string;
    children: ReactNode;
}

export function ExampleSection({ label, children, ...rest }: Props) {
    return (
        <div className={styles.section} data-layout="ExampleSection" {...rest}>
            <div className={styles.label}>{label}</div>
            {children}
        </div>
    );
}

import type { ReactNode } from "react";
import styles from "./SwatchGrid.module.css";

interface Props {
    children: ReactNode;
}

export function SwatchGrid({ children }: Props) {
    return <div className={styles.swatchGrid} data-layout="SwatchGrid">{children}</div>;
}
